// Basic Raymarching SDF Scene — GLSL TOP Pixel Shader
// Inputs: TDOutputSwizzle for proper output
// Uniforms: uTime (float, drives animation)

uniform float uTime;

// --- SDF Primitives ---
float sdSphere(vec3 p, float r) {
    return length(p) - r;
}

float sdBox(vec3 p, vec3 b) {
    vec3 q = abs(p) - b;
    return length(max(q, 0.0)) + min(max(q.x, max(q.y, q.z)), 0.0);
}

float sdTorus(vec3 p, vec2 t) {
    vec2 q = vec2(length(p.xz) - t.x, p.y);
    return length(q) - t.y;
}

// --- Smooth Boolean Operations ---
float opSmoothUnion(float d1, float d2, float k) {
    float h = clamp(0.5 + 0.5 * (d2 - d1) / k, 0.0, 1.0);
    return mix(d2, d1, h) - k * h * (1.0 - h);
}

// --- Scene SDF ---
float sceneSDF(vec3 p) {
    // Animated sphere
    vec3 sp = p - vec3(sin(uTime * 0.7) * 0.5, cos(uTime * 0.5) * 0.3, 0.0);
    float sphere = sdSphere(sp, 0.4);

    // Static torus
    vec3 tp = p - vec3(0.0, -0.5, 0.0);
    tp = vec3(tp.x, tp.z, tp.y); // rotate to XZ plane
    float torus = sdTorus(tp, vec2(0.6, 0.15));

    return opSmoothUnion(sphere, torus, 0.3);
}

// --- Normal via Central Differences ---
vec3 calcNormal(vec3 p) {
    const float eps = 0.001;
    return normalize(vec3(
        sceneSDF(p + vec3(eps, 0, 0)) - sceneSDF(p - vec3(eps, 0, 0)),
        sceneSDF(p + vec3(0, eps, 0)) - sceneSDF(p - vec3(0, eps, 0)),
        sceneSDF(p + vec3(0, 0, eps)) - sceneSDF(p - vec3(0, 0, eps))
    ));
}

// --- Raymarcher ---
float raymarch(vec3 ro, vec3 rd) {
    float t = 0.0;
    for (int i = 0; i < 96; i++) {
        float d = sceneSDF(ro + rd * t);
        if (d < 0.001) return t;
        if (t > 20.0) break;
        t += d;
    }
    return -1.0;
}

out vec4 fragColor;
void main() {
    vec2 uv = vUV.st * 2.0 - 1.0;
    uv.x *= uTD2DInfos[0].res.x / uTD2DInfos[0].res.y; // aspect correct

    // Camera setup
    vec3 ro = vec3(0.0, 0.0, 2.5);       // ray origin
    vec3 rd = normalize(vec3(uv, -1.5)); // ray direction

    vec3 col = vec3(0.05, 0.05, 0.12);   // background

    float t = raymarch(ro, rd);
    if (t > 0.0) {
        vec3 pos = ro + rd * t;
        vec3 nor = calcNormal(pos);

        // Lighting
        vec3 light = normalize(vec3(1.0, 2.0, 3.0));
        float diff = max(dot(nor, light), 0.0);
        float spec = pow(max(dot(reflect(-light, nor), -rd), 0.0), 32.0);

        col = vec3(0.3, 0.6, 0.9) * diff + vec3(1.0) * spec * 0.5;
        col += vec3(0.05, 0.05, 0.15); // ambient

        // Fog
        col = mix(col, vec3(0.05, 0.05, 0.12), 1.0 - exp(-t * 0.1));
    }

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

// Domain Repetition — infinite grid of objects
uniform float uTime;
uniform float uSpacing; // cell spacing, e.g. 2.0

float sdSphere(vec3 p, float r) { return length(p) - r; }

// Repeat space with cell size c
vec3 opRepeat(vec3 p, vec3 c) {
    return mod(p + 0.5 * c, c) - 0.5 * c;
}

// Limited repetition (N repetitions per axis)
vec3 opRepeatLim(vec3 p, float c, vec3 lim) {
    return p - c * clamp(round(p / c), -lim, lim);
}

// Domain warping — FBM-based displacement
vec3 domainWarp(vec3 p, float strength) {
    float t = uTime * 0.3;
    return p + strength * vec3(
        sin(p.y * 2.1 + t) * cos(p.z * 1.7),
        sin(p.z * 1.9 + t * 1.1) * cos(p.x * 2.3),
        sin(p.x * 2.5 + t * 0.9) * cos(p.y * 1.5)
    );
}

float scene(vec3 p) {
    vec3 wp = domainWarp(p, 0.15);
    vec3 rp = opRepeat(wp, vec3(uSpacing));
    return sdSphere(rp, 0.3 + sin(uTime + length(floor(p / uSpacing))) * 0.1);
}

// Gray-Scott Reaction-Diffusion — GLSL TOP
// Input 0: previous state (Feedback TOP) — RG channels = A,B concentrations
// Uniforms: F (feed rate), K (kill rate), dA, dB (diffusion rates)

uniform float uF;   // feed rate  (e.g. 0.055)
uniform float uK;   // kill rate  (e.g. 0.062)
uniform float uDa;  // diffusion A (e.g. 1.0)
uniform float uDb;  // diffusion B (e.g. 0.5)
uniform float uDt;  // timestep   (e.g. 1.0)
uniform float uSeed; // used for initial noise seeding

vec2 texel;

vec4 sampleState(vec2 uv) {
    return texture(sTD2DInputs[0], uv);
}

void main() {
    texel = 1.0 / uTD2DInfos[0].res.zw;
    vec2 uv = vUV.st;

    // Laplacian (5-tap)
    vec4 center = sampleState(uv);
    vec4 left   = sampleState(uv + vec2(-texel.x, 0.0));
    vec4 right  = sampleState(uv + vec2( texel.x, 0.0));
    vec4 up     = sampleState(uv + vec2(0.0,  texel.y));
    vec4 down   = sampleState(uv + vec2(0.0, -texel.y));

    float a = center.r;
    float b = center.g;

    float lapA = (left.r + right.r + up.r + down.r) - 4.0 * a;
    float lapB = (left.g + right.g + up.g + down.g) - 4.0 * b;

    float reaction = a * b * b;

    float newA = a + uDt * (uDa * lapA - reaction + uF * (1.0 - a));
    float newB = b + uDt * (uDb * lapB + reaction - (uK + uF) * b);

    newA = clamp(newA, 0.0, 1.0);
    newB = clamp(newB, 0.0, 1.0);

    fragColor = TDOutputSwizzle(vec4(newA, newB, 0.0, 1.0));
}

