// Colorize reaction-diffusion output
// Input 0: RD state (A=R, B=G)
void main() {
    vec4 state = texture(sTD2DInputs[0], vUV.st);
    float a = state.r;
    float b = state.g;
    float t = b; // highlight B concentration

    // Palette: deep blue -> cyan -> white
    vec3 col = mix(
        mix(vec3(0.02, 0.05, 0.2), vec3(0.0, 0.8, 0.9), t * 2.0),
        vec3(1.0),
        max(0.0, t * 2.0 - 1.0)
    );
    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

