// Feedback Zoom + Rotate + Decay
// Input 0: current live source (Camera/Video)
// Input 1: Feedback TOP (previous frame after effects)
uniform float uDecay;  // e.g. 0.95
uniform float uZoom;   // e.g. 1.005  (>1 zooms in)
uniform float uRotate; // rotation in radians per frame, e.g. 0.002
uniform float uMix;    // blend live vs feedback, e.g. 0.15

void main() {
    vec2 uv = vUV.st;
    vec2 center = vec2(0.5);

    // Apply zoom and rotation to feedback UV
    vec2 offset = uv - center;
    float c = cos(uRotate);
    float s = sin(uRotate);
    offset = vec2(c * offset.x - s * offset.y,
                  s * offset.x + c * offset.y);
    offset /= uZoom;
    vec2 fbUV = offset + center;

    vec4 live = texture(sTD2DInputs[0], uv);
    vec4 fb   = texture(sTD2DInputs[1], fbUV) * uDecay;

    fragColor = TDOutputSwizzle(mix(fb, live, uMix));
}

// Procedural FBM Noise — GLSL TOP
uniform float uTime;
uniform float uScale;    // overall scale, e.g. 3.0
uniform int   uOctaves;  // 1..8
uniform float uLacunarity; // frequency multiplier, e.g. 2.0
uniform float uGain;     // amplitude multiplier, e.g. 0.5

// Value noise hash
vec2 hash2(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)),
             dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453);
}

// Gradient noise (Perlin-like)
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f * f * (3.0 - 2.0 * f); // smoothstep

    float a = dot(hash2(i + vec2(0,0)) * 2.0 - 1.0, f - vec2(0,0));
    float b = dot(hash2(i + vec2(1,0)) * 2.0 - 1.0, f - vec2(1,0));
    float c = dot(hash2(i + vec2(0,1)) * 2.0 - 1.0, f - vec2(0,1));
    float d = dot(hash2(i + vec2(1,1)) * 2.0 - 1.0, f - vec2(1,1));

    return mix(mix(a, b, u.x), mix(c, d, u.x), u.y);
}

// fBm — layered octaves of noise
float fbm(vec2 p) {
    float value = 0.0;
    float amplitude = 0.5;
    float frequency = 1.0;

    for (int i = 0; i < 8; i++) {
        if (i >= uOctaves) break;
        value += amplitude * noise(p * frequency);
        frequency *= uLacunarity;
        amplitude *= uGain;
    }
    return value;
}

// Domain-warped fBm for extra complexity
float warpedFbm(vec2 p) {
    vec2 q = vec2(fbm(p), fbm(p + vec2(5.2, 1.3)));
    return fbm(p + 4.0 * q);
}

void main() {
    vec2 uv = vUV.st;
    vec2 p = uv * uScale + vec2(uTime * 0.05);

    float n = warpedFbm(p) * 0.5 + 0.5;

    // Cloud-like coloring
    vec3 colA = vec3(0.12, 0.18, 0.35);
    vec3 colB = vec3(0.9, 0.95, 1.0);
    vec3 col = mix(colA, colB, smoothstep(0.3, 0.75, n));

    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

// Voronoi / Cellular Noise — GLSL TOP
uniform float uTime;
uniform float uScale; // e.g. 8.0
uniform float uAnim;  // animation speed, e.g. 0.3

vec2 hash2(vec2 p) {
    return fract(sin(vec2(
        dot(p, vec2(127.1, 311.7)),
        dot(p, vec2(269.5, 183.3))
    )) * 43758.5453);
}

// Returns vec2(F1, F2) — distance to nearest and second-nearest cell
vec2 voronoi(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);

    float F1 = 8.0, F2 = 8.0;

    for (int y = -2; y <= 2; y++) {
        for (int x = -2; x <= 2; x++) {
            vec2 neighbor = vec2(x, y);
            vec2 point = hash2(i + neighbor);
            point = 0.5 + 0.5 * sin(uTime * uAnim + 6.2831 * point);
            vec2 diff = neighbor + point - f;
            float d = length(diff);
            if (d < F1) { F2 = F1; F1 = d; }
            else if (d < F2) { F2 = d; }
        }
    }
    return vec2(F1, F2);
}

void main() {
    vec2 uv = vUV.st * uScale;
    vec2 F = voronoi(uv);

    float border = smoothstep(0.0, 0.08, F.y - F.x);
    float cell = F.x;

    vec3 col = mix(vec3(0.02), vec3(0.5 + 0.5 * cell, 0.7, 0.9), border);
    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}

// GLSL Multi TOP — outputs albedo, normals, depth in one pass
// Set 'Outputs' parameter to 3 in GLSL Multi TOP

uniform float uTime;

layout(location = 0) out vec4 outAlbedo;
layout(location = 1) out vec4 outNormal;
layout(location = 2) out vec4 outDepth;

void main() {
    vec2 uv = vUV.st;

    // Example: output different data per channel
    vec3 albedo = vec3(uv, sin(uTime) * 0.5 + 0.5);
    vec3 normal = normalize(vec3(uv * 2.0 - 1.0, 1.0));
    float depth = uv.x; // simplified

    outAlbedo = TDOutputSwizzle(vec4(albedo, 1.0));
    outNormal = TDOutputSwizzle(vec4(normal * 0.5 + 0.5, 1.0));
    outDepth  = TDOutputSwizzle(vec4(depth, depth, depth, 1.0));
}
